// ❌ BAD - no rate limiting, payment endpoint open to abuse
app.MapPost("/payments", ProcessPayment);

// ✅ GOOD - sliding window, 100 calls per minute, 429 on excess
builder.Services.AddRateLimiter(o =>
    o.AddSlidingWindowLimiter("payments", opt => {
        opt.PermitLimit = 100;
        opt.Window = TimeSpan.FromMinutes(1);
        opt.SegmentsPerWindow = 6;
    }));
app.UseRateLimiter();
app.MapPost("/payments", ProcessPayment)
   .RequireRateLimiting("payments");

