// ❌ BAD - returning 200 with an error body confuses clients and monitoring tools
return Ok(new { error = "Order not found" });

// ✅ GOOD - correct status codes tell clients and load balancers what happened
var order = await _orderRepo.FindAsync(orderId);
if (order is null) return NotFound();
if (!order.BelongsTo(currentUserId)) return Forbid();
return Ok(order);

// ❌ BAD - fires all 500 requests at once, will exhaust the HTTP client pool
var tasks = orderIds.Select(id => _client.GetAsync($"/inventory/{id}"));
await Task.WhenAll(tasks);

// ✅ GOOD - caps at 10 concurrent inventory checks
await Parallel.ForEachAsync(
    orderIds,
    new ParallelOptions { MaxDegreeOfParallelism = 10 },
    async (id, ct) =>
        await _client.GetAsync($"/inventory/{id}", ct));

// ❌ BAD - blocks the calling thread, risks deadlock or starvation
var report = _reportService.GenerateAsync(dateRange).Result;

// ✅ GOOD - frees the thread while awaiting, scales under load
var report = await _reportService.GenerateAsync(dateRange);

// In library/infrastructure code - avoid capturing the context
var data = await _db.GetSalesAsync().ConfigureAwait(false);

