// ❌ BAD - IActionResult hides the response type from Swagger and callers
public IActionResult GetProduct(int id)
{
    var product = _catalog.Find(id);
    if (product is null) return NotFound();
    return Ok(product); // Swagger shows 200 with unknown body type
}

// ✅ GOOD - ActionResult<T> documents the success type for OpenAPI
public ActionResult<Product> GetProduct(int id)
{
    var product = _catalog.Find(id);
    if (product is null) return NotFound();
    return product; // implicit 200 with typed Product body
}

// ❌ BAD - middleware cannot access typed action arguments
app.Use(async (ctx, next) => {
    // ctx has no way to read the bound 'customerId' action parameter
    await next();
});

// ✅ GOOD - action filter has access to bound arguments after model binding
public class OrderAuditFilter : IActionFilter
{
    public void OnActionExecuting(ActionExecutingContext ctx)
    {
        var orderId = ctx.ActionArguments["orderId"] as int?;
        _audit.Log($"Order {orderId} accessed by {ctx.HttpContext.User.Identity.Name}");
    }
    public void OnActionExecuted(ActionExecutedContext ctx) { }
}

// ❌ BAD - action filter for caching means model binding already ran (wasted work)
public class ReportCacheFilter : IActionFilter {
    public void OnActionExecuting(ActionExecutingContext ctx) {
        if (_cache.TryGet(key, out var val)) ctx.Result = new OkObjectResult(val);
    }
    public void OnActionExecuted(ActionExecutedContext ctx) { }
}

// ✅ GOOD - resource filter short-circuits before binding runs at all
public class ReportCacheFilter : IResourceFilter {
    public void OnResourceExecuting(ResourceExecutingContext ctx) {
        if (_cache.TryGet(key, out var val)) ctx.Result = new OkObjectResult(val);
    }
    public void OnResourceExecuted(ResourceExecutedContext ctx) { }
}
